head.script:
//
tailwind.config = {
  theme: {
    extend: {
      fontFamily: {
        sans: ['Inter', 'sans-serif'],
        display: ['Space Grotesk', 'sans-serif'],
      },
      colors: {
        primary: '#6b705c', // Sage Green
        accent: '#cb997e',  // Warm Terracotta
        charcoal: '#1d1d1f' // Apple Black
      },
      screens: {
        '3xl': '1920px',
        '4xl': '2560px',
        '5xl': '3840px'
      }
    }
  }
}
//

head.b:skin:
/* Apple-style Smooth Parallax Custom Core Styles */
html {
  scroll-behavior: smooth;
}

body {
  font-family: 'Inter', sans-serif;
  background-color: #fbfbf9;
  color: #1d1d1f;
  overflow-x: hidden;
  margin: 0;
  padding: 0;
  transition: background-color 0.3s ease;
}

/* 4K & Ultra-Wide Display Optimizations - Proportional scaling to prevent horizontal stretching */
@media (min-width: 1920px) {
  .max-w-7xl { max-width: 1360px !important; }
  .max-w-6xl { max-width: 1200px !important; }
  .max-w-5xl { max-width: 1080px !important; }
  .max-w-4xl { max-width: 900px !important; }
  body { font-size: 16px; }
}
@media (min-width: 2560px) {
  .max-w-7xl { max-width: 1440px !important; }
  .max-w-6xl { max-width: 1280px !important; }
  .max-w-5xl { max-width: 1120px !important; }
  .max-w-4xl { max-width: 960px !important; }
  body { font-size: 18px; }
}
@media (min-width: 3840px) {
  .max-w-7xl { max-width: 1600px !important; }
  .max-w-6xl { max-width: 1400px !important; }
  .max-w-5xl { max-width: 1200px !important; }
  .max-w-4xl { max-width: 1000px !important; }
  body { font-size: 22px; }
}

/* Floating Keyframe Animation */
@keyframes float-y {
  0%, 100% { transform: translateY(0px); }
  50% { transform: translateY(-14px); }
}
.animate-float {
  animation: float-y 6s ease-in-out infinite;
}
.animate-float-delay {
  animation: float-y 6s ease-in-out infinite;
  animation-delay: 3s;
}

/* Out-of-sync Gentle Bobbing/Swaying Animations for Dashboard Cards */
@keyframes bob-gentle-1 {
  0%, 100% { transform: translateY(0px); }
  50% { transform: translateY(-10px); }
}
@keyframes bob-gentle-2 {
  0%, 100% { transform: translateY(0px); }
  50% { transform: translateY(-7px); }
}
@keyframes bob-gentle-3 {
  0%, 100% { transform: translateY(0px); }
  50% { transform: translateY(-12px); }
}
.animate-bob-1 {
  animation: bob-gentle-1 5.5s ease-in-out infinite;
}
.animate-bob-2 {
  animation: bob-gentle-2 6.5s ease-in-out infinite;
}
.animate-bob-3 {
  animation: bob-gentle-3 6s ease-in-out infinite;
}

/* Error Shake Animation */
@keyframes shake {
  0%, 100% { transform: translateX(0); }
  25% { transform: translateX(-5px); }
  75% { transform: translateX(5px); }
}
.shake-element {
  animation: shake 0.25s ease-in-out 2;
}

/* Organic Floating Background Glow Blobs */
@keyframes drift-blob-1 {
  0%, 100% { transform: translate(0px, 0px) scale(1); }
  33% { transform: translate(120px, -80px) scale(1.2); }
  66% { transform: translate(-60px, 100px) scale(0.85); }
}
@keyframes drift-blob-2 {
  0%, 100% { transform: translate(0px, 0px) scale(1); }
  50% { transform: translate(-100px, 120px) scale(1.25); }
}
@keyframes drift-blob-3 {
  0%, 100% { transform: translate(0px, 0px) scale(1); }
  40% { transform: translate(80px, 90px) scale(0.9); }
}
.animate-drift-1 {
  animation: drift-blob-1 25s ease-in-out infinite;
}
.animate-drift-2 {
  animation: drift-blob-2 30s ease-in-out infinite;
}
.animate-drift-3 {
  animation: drift-blob-3 28s ease-in-out infinite;
}

/* 3D Isometric Cards with Preservation of Depth and custom rotation */
.isometric-container {
  perspective: 1500px;
}
.isometric-card {
  transform: rotateX(20deg) rotateY(-12deg) rotateZ(3deg);
  transform-style: preserve-3d;
  transition: all 1s cubic-bezier(0.16, 1, 0.3, 1);
}
.isometric-card:hover {
  transform: rotateX(10deg) rotateY(-4deg) rotateZ(0deg) translateY(-12px);
  box-shadow: 0 50px 100px -20px rgba(107, 112, 92, 0.22), 0 30px 60px -15px rgba(203, 153, 126, 0.14);
}
.isometric-card-right {
  transform: rotateX(20deg) rotateY(12deg) rotateZ(-3deg);
  transform-style: preserve-3d;
  transition: all 1s cubic-bezier(0.16, 1, 0.3, 1);
}
.isometric-card-right:hover {
  transform: rotateX(10deg) rotateY(4deg) rotateZ(0deg) translateY(-12px);
  box-shadow: 0 50px 100px -20px rgba(203, 153, 126, 0.22), 0 30px 60px -15px rgba(107, 112, 92, 0.14);
}

/* Glassmorphism navigation */
.glass-nav {
  background: rgba(251, 251, 249, 0.8);
  backdrop-filter: blur(20px);
  -webkit-backdrop-filter: blur(20px);
  border-bottom: 1px solid rgba(0, 0, 0, 0.05);
}

/* Standard Blogger Layout Overrides to Hide Default Widgets and Navbar */
#navbar-iframe, .navbar, .header-outer, .sidebar-outer, .footer-outer, .post-share-buttons {
  display: none !important;
  visibility: hidden !important;
}

.status-msg-wrap {
  display: none !important;
}

/* Interactive animations & custom visual effects */
.hero-gradient {
  background: radial-gradient(circle at 50% 50%, rgba(107, 112, 92, 0.08) 0%, transparent 60%);
}

.apple-card-hover {
  transition: all 0.6s cubic-bezier(0.16, 1, 0.3, 1);
}
.apple-card-hover:hover {
  transform: translateY(-10px) scale(1.02);
  box-shadow: 0 40px 80px -20px rgba(0,0,0,0.1);
}

/* Scroll animations */
.scroll-reveal {
  opacity: 0;
  transform: translateY(40px);
  transition: opacity 1.2s cubic-bezier(0.16, 1, 0.3, 1), transform 1.2s cubic-bezier(0.16, 1, 0.3, 1);
}
.scroll-reveal.active {
  opacity: 1;
  transform: translateY(0);
}

/* Custom Input Range styling */
input[type="range"] {
  -webkit-appearance: none;
  appearance: none;
  width: 100%;
  height: 6px;
  background: #e5e1d8;
  border-radius: 999px;
  outline: none;
}
input[type="range"]::-webkit-slider-thumb {
  -webkit-appearance: none;
  appearance: none;
  width: 18px;
  height: 18px;
  border-radius: 50%;
  background: #6b705c;
  cursor: pointer;
  transition: transform 0.1s ease;
  box-shadow: 0 2px 6px rgba(0,0,0,0.15);
}
input[type="range"]::-webkit-slider-thumb:hover {
  transform: scale(1.2);
}

/* Premium shadow effects & Glows */
.shadow-premium {
  box-shadow: 0 30px 60px -15px rgba(107, 112, 92, 0.12), 0 15px 30px -10px rgba(203, 153, 126, 0.08);
}
.shadow-premium-hover {
  transition: all 0.6s cubic-bezier(0.16, 1, 0.3, 1);
}
.shadow-premium-hover:hover {
  transform: translateY(-8px) scale(1.01);
  box-shadow: 0 40px 80px -20px rgba(107, 112, 92, 0.18), 0 20px 40px -15px rgba(203, 153, 126, 0.12);
}

/* Standardized typography and prose style for Blogger pages */
.post-body-content p, .prose p {
  margin-bottom: 1.5rem;
  line-height: 1.8;
}
.post-body-content h2, .prose h2 {
  font-family: 'Space Grotesk', sans-serif;
  font-weight: 700;
  font-size: 1.5rem;
  color: #1d1d1f;
  margin-top: 2.5rem;
  margin-bottom: 1rem;
}
.post-body-content ul, .prose ul {
  list-style-type: disc;
  padding-left: 1.5rem;
  margin-bottom: 1.5rem;
}
.post-body-content li, .prose li {
  margin-bottom: 0.5rem;
}

/* Apple-style Scroll-triggered Typography Highlight */
.apple-word {
  color: rgba(255, 255, 255, 0.12);
  transition: color 0.4s cubic-bezier(0.16, 1, 0.3, 1), transform 0.4s cubic-bezier(0.16, 1, 0.3, 1);
  display: inline-block;
  transform: translateY(2px);
}
.apple-word.active {
  color: #ffffff;
  transform: translateY(0px);
}
.apple-word.active[data-accent="terapist"] {
  color: #cb997e;
  text-shadow: 0 0 40px rgba(203, 153, 126, 0.25);
}
.apple-word.active[data-accent="akilli"] {
  color: #a3b18a;
  text-shadow: 0 0 40px rgba(163, 177, 138, 0.25);
}

/* Scrollytelling for Defter Devri Kapanıyor Heading */
.scrolly-word {
  color: rgba(255, 255, 255, 0.15);
  transition: color 0.4s cubic-bezier(0.16, 1, 0.3, 1), transform 0.4s cubic-bezier(0.16, 1, 0.3, 1);
  display: inline-block;
  transform: translateY(4px);
}
.scrolly-word.active {
  color: #ffffff;
  transform: translateY(0px);
}
.scrolly-word.active[data-accent="defter"] {
  color: #f87171;
  text-shadow: 0 0 30px rgba(248, 113, 113, 0.2);
}
.scrolly-word.active[data-accent="kapanıyor"] {
  color: #cbd5e1;
}
.scrolly-word.active[data-accent="akilli"] {
  color: #cb997e;
  text-shadow: 0 0 30px rgba(203, 153, 126, 0.25);
}
.scrolly-word.active[data-accent="cagi"] {
  color: #a3b18a;
  text-shadow: 0 0 30px rgba(163, 177, 138, 0.25);
}
.scrolly-word.active[data-accent="keşfedin"] {
  color: #34d399;
  text-shadow: 0 0 30px rgba(52, 211, 153, 0.25);
}

/* Infinite sliding carousel for related posts (controlled dynamically in JS for manual dragging) */
.carousel-track {
  display: flex;
  width: max-content;
}

body.script:
//
// Device detection
const isMobile = /Android|webOS|iPhone|iPad|iPod|BlackBerry|IEMobile|Opera Mini/i.test(navigator.userAgent);

// High-performance Scroll Reveal using IntersectionObserver
const revealElements = document.querySelectorAll('.scroll-reveal');
function initScrollReveal() {
  if ('IntersectionObserver' in window) {
    const observerOptions = {
      root: null, // viewport
      rootMargin: '0px 0px -60px 0px', // slightly offset trigger height
      threshold: 0.05 // trigger as soon as 5% is visible
    };
    const revealObserver = new IntersectionObserver((entries, observer) => {
      entries.forEach(entry => {
        if (entry.isIntersecting) {
          entry.target.classList.add('active');
          observer.unobserve(entry.target); // Unobserve once shown for absolute peak performance
        }
      });
    }, observerOptions);
    revealElements.forEach(el => revealObserver.observe(el));
  } else {
    // Fallback for older legacy browsers
    const handleScrollRevealFallback = () => {
      revealElements.forEach(el => {
        const rect = el.getBoundingClientRect();
        if (rect.top < window.innerHeight - 60) {
          el.classList.add('active');
        }
      });
    };
    window.addEventListener('scroll', handleScrollRevealFallback, { passive: true });
    handleScrollRevealFallback();
  }
}

// Apple-style scroll-triggered typography highlight effect
const introSection = document.getElementById('welcome-intro-section');
const introTrack = document.getElementById('welcome-intro-track');
const appleWords = document.querySelectorAll('.apple-word');

function handleAppleTypographyScroll() {
  if (!introTrack || !introSection || appleWords.length === 0) return;

  const viewportHeight = window.innerHeight;
  const trackHeight = introTrack.offsetHeight;
  const trackTop = introTrack.offsetTop || 0;

  const totalScrollable = trackHeight - viewportHeight;
  const currentScrolled = currentScrollY - trackTop;

  let progress = currentScrolled / totalScrollable;
  progress = Math.min(Math.max(progress, 0), 1);

  // Shift grid vertically to give physical sense of flow / sliding
  // Skip transformation entirely on mobile to bypass expensive rendering calculations
  const introGrid = document.getElementById('intro-grid');
  if (!isMobile && introGrid) {
    const gridY = -progress * 140; 
    introGrid.style.transform = `scale(1.15) rotateX(12deg) translate3d(0, ${gridY}px, 0)`;
  }

  const scrollIndicator = document.getElementById('scroll-indicator');
  if (scrollIndicator) {
    // Fade out indicator smoothly once user begins scrolling
    if (progress > 0.03) {
      scrollIndicator.style.opacity = '0';
      scrollIndicator.style.transform = 'translate3d(-50%, 20px, 0)';
    } else {
      scrollIndicator.style.opacity = '1';
      scrollIndicator.style.transform = 'translate3d(-50%, 0, 0)';
    }
  }

  // High-performance SVG Flow paths - completely bypassed on mobile because SVG paths are hidden
  if (!isMobile) {
    const shape1 = document.getElementById('flow-shape-1');
    const shape2 = document.getElementById('flow-shape-2');
    const shape3 = document.getElementById('flow-shape-3');

    if (shape1) {
      const tx = progress * 200 - 60; 
      const ty = -progress * 150;
      const scale = 1 + progress * 0.3;
      const rotate = progress * 25;
      shape1.style.transform = `translate3d(${tx}px, ${ty}px, 0) scale(${scale}) rotate(${rotate}deg)`;
      shape1.style.transformOrigin = 'center center';
    }
    if (shape2) {
      const tx = -progress * 250 + 40;
      const ty = progress * 160;
      const scale = 1.15 - progress * 0.2;
      const rotate = -progress * 30;
      shape2.style.transform = `translate3d(${tx}px, ${ty}px, 0) scale(${scale}) rotate(${rotate}deg)`;
      shape2.style.transformOrigin = 'center center';
    }
    if (shape3) {
      const tx = progress * 150 - 80;
      const ty = -progress * 200 + 50;
      const scale = 0.9 + progress * 0.4;
      const rotate = progress * 40;
      shape3.style.transform = `translate3d(${tx}px, ${ty}px, 0) scale(${scale}) rotate(${rotate}deg)`;
      shape3.style.transformOrigin = 'center center';
    }
  }

  // Hardware-accelerated cross-fading of layered backgrounds with smoothstep bezier curve
  const bgStart = document.getElementById('intro-bg-start');
  const bgMid = document.getElementById('intro-bg-mid');
  const bgEnd = document.getElementById('intro-bg-end');

  if (bgStart && bgMid && bgEnd) {
    let opStart = 0;
    let opMid = 0;
    let opEnd = 0;

    if (progress <= 0.5) {
      const p = progress / 0.5; // 0 to 1
      const smoothP = p * p * (3 - 2 * p); // Smoothstep curve
      opStart = 1 - smoothP;
      opMid = smoothP;
      opEnd = 0;
    } else {
      const p = (progress - 0.5) / 0.5; // 0 to 1
      const smoothP = p * p * (3 - 2 * p); // Smoothstep curve
      opStart = 0;
      opMid = 1 - smoothP;
      opEnd = smoothP;
    }

    bgStart.style.opacity = opStart.toFixed(3);
    bgMid.style.opacity = opMid.toFixed(3);
    bgEnd.style.opacity = opEnd.toFixed(3);
  }

  // Scale progress slightly to have a buffer at start and end
  const startBuffer = 0.05;
  const endBuffer = 0.95;
  let wordProgress = 0;
  if (progress >= startBuffer) {
    wordProgress = (progress - startBuffer) / (endBuffer - startBuffer);
    wordProgress = Math.min(Math.max(wordProgress, 0), 1);
  }

  const totalWords = appleWords.length;
  appleWords.forEach((word, index) => {
    const threshold = index / totalWords;
    if (wordProgress >= threshold) {
      word.classList.add('active');
    } else {
      word.classList.remove('active');
    }
  });

  // Digital Agenda Scrollytelling Title Animation
  handleDigitalAgendaScrollytelling();
}

const digitalSection = document.getElementById('digital-agenda');
const scrollyWords = document.querySelectorAll('.scrolly-word');

function handleDigitalAgendaScrollytelling() {
  if (!digitalSection || scrollyWords.length === 0) return;

  const viewportHeight = window.innerHeight;
  const sectionHeight = digitalSection.offsetHeight;
  const sectionTop = digitalSection.offsetTop || 0;

  // We want the highlighting to occur as the section enters the viewport
  const startScroll = sectionTop - viewportHeight;
  const endScroll = sectionTop + sectionHeight * 0.15;

  let progress = (currentScrollY - startScroll) / (endScroll - startScroll);
  progress = Math.min(Math.max(progress, 0), 1);

  const totalWords = scrollyWords.length;
  scrollyWords.forEach((word, index) => {
    const threshold = index / totalWords;
    if (progress >= threshold) {
      word.classList.add('active');
    } else {
      word.classList.remove('active');
    }
  });
}

function handleShowcaseScrollytelling() {
  const showcaseTrack = document.getElementById('showcase-scrolly-track');
  if (!showcaseTrack) return;

  const rect = showcaseTrack.getBoundingClientRect();
  // Calculate absolute top Y coordinate relative to the document, bypassing offsetParent limitations
  const trackTop = rect.top + window.scrollY;
  const trackHeight = showcaseTrack.offsetHeight;
  const viewportHeight = window.innerHeight;

  const startScroll = trackTop;
  const endScroll = trackTop + trackHeight - viewportHeight;
  let progress = (currentScrollY - startScroll) / (trackHeight - viewportHeight);
  progress = Math.min(Math.max(progress, 0), 1);

  // Map progress to active step
  let activeStep = 0;
  if (progress < 0.2) activeStep = 0;
  else if (progress < 0.4) activeStep = 1;
  else if (progress < 0.6) activeStep = 2;
  else if (progress < 0.8) activeStep = 3;
  else activeStep = 4;

  // 1. Text Steps Cross-fade
  for (let i = 0; i <= 4; i++) {
    const textEl = document.getElementById(`scrolly-step-text-${i}`);
    if (textEl) {
      if (i === activeStep) {
        textEl.style.opacity = '1';
        textEl.style.transform = 'translate3d(0, 0, 0)';
        textEl.style.pointerEvents = 'auto';
      } else {
        textEl.style.opacity = '0';
        textEl.style.transform = i < activeStep ? 'translate3d(0, -20px, 0)' : 'translate3d(0, 20px, 0)';
        textEl.style.pointerEvents = 'none';
      }
    }
  }

  // 2. Active Dot Indicator
  const dots = document.querySelectorAll('#scrolly-dots-indicator [data-dot]');
  dots.forEach((dot, idx) => {
    const dNum = parseInt(dot.getAttribute('data-dot'));
    if (dNum === activeStep) {
      dot.className = 'w-4 h-2 rounded-full bg-[#cb997e] transition-all duration-300';
    } else {
      dot.className = 'w-2 h-2 rounded-full bg-slate-200 transition-all duration-300';
    }
  });

  // 3. Ambient Glow Offset based on scroll
  const glow1 = document.getElementById('scrolly-glow-1');
  const glow2 = document.getElementById('scrolly-glow-2');
  if (glow1) {
    glow1.style.transform = `translate3d(${progress * 50}px, ${-progress * 30}px, 0)`;
  }
  if (glow2) {
    glow2.style.transform = `translate3d(${-progress * 60}px, ${progress * 40}px, 0)`;
  }

  // 4. Transform Cards based on Active Step
  const cardRooms = document.getElementById('scrolly-card-rooms');
  const cardEarnings = document.getElementById('scrolly-card-earnings');
  const cardActivity = document.getElementById('scrolly-card-activity');
  const visualIsometricGroup = document.getElementById('scrolly-visual-isometric-group');
  const visualSimulator = document.getElementById('scrolly-visual-simulator');

  if (activeStep < 4) {
    // Show Isometric Group, Hide Simulator
    if (visualIsometricGroup) {
      visualIsometricGroup.style.opacity = '1';
      visualIsometricGroup.style.pointerEvents = 'auto';
      visualIsometricGroup.style.transform = 'scale(1)';
    }
    if (visualSimulator) {
      visualSimulator.style.opacity = '0';
      visualSimulator.style.pointerEvents = 'none';
      visualSimulator.style.transform = 'scale(0.95)';
    }

    // Reset card properties based on sub-steps
    if (cardRooms && cardEarnings && cardActivity) {
      if (activeStep === 0) {
        // General overview (3D Balanced)
        cardRooms.style.transform = 'rotateX(12deg) rotateY(-10deg) scale(1) translate3d(0, 0, 0)';
        cardRooms.style.opacity = '1';
        cardRooms.style.filter = 'none';
        cardRooms.style.zIndex = '10';

        cardEarnings.style.transform = 'scale(1.05) translate3d(0, 0, 0)';
        cardEarnings.style.opacity = '1';
        cardEarnings.style.filter = 'none';
        cardEarnings.style.zIndex = '20';

        cardActivity.style.transform = 'rotateX(12deg) rotateY(10deg) scale(1) translate3d(0, 0, 0)';
        cardActivity.style.opacity = '1';
        cardActivity.style.filter = 'none';
        cardActivity.style.zIndex = '10';
      } else if (activeStep === 1) {
        // Focus on Rooms card
        cardRooms.style.transform = 'rotateX(0deg) rotateY(0deg) scale(1.1) translate3d(20px, 0, 0)';
        cardRooms.style.opacity = '1';
        cardRooms.style.filter = 'none';
        cardRooms.style.zIndex = '30';

        cardEarnings.style.transform = 'scale(0.85) translate3d(-10px, 0, 0)';
        cardEarnings.style.opacity = '0.25';
        cardEarnings.style.filter = 'blur(2px)';
        cardEarnings.style.zIndex = '10';

        cardActivity.style.transform = 'rotateX(10deg) rotateY(10deg) scale(0.8) translate3d(-20px, 0, 0)';
        cardActivity.style.opacity = '0.2';
        cardActivity.style.filter = 'blur(3px)';
        cardActivity.style.zIndex = '5';
      } else if (activeStep === 2) {
        // Focus on Earnings card
        cardRooms.style.transform = 'rotateX(10deg) rotateY(-10deg) scale(0.8) translate3d(20px, 0, 0)';
        cardRooms.style.opacity = '0.2';
        cardRooms.style.filter = 'blur(3px)';
        cardRooms.style.zIndex = '5';

        cardEarnings.style.transform = 'scale(1.15) translate3d(0, 0, 0)';
        cardEarnings.style.opacity = '1';
        cardEarnings.style.filter = 'none';
        cardEarnings.style.zIndex = '30';

        cardActivity.style.transform = 'rotateX(10deg) rotateY(10deg) scale(0.8) translate3d(-20px, 0, 0)';
        cardActivity.style.opacity = '0.2';
        cardActivity.style.filter = 'blur(3px)';
        cardActivity.style.zIndex = '5';
      } else if (activeStep === 3) {
        // Focus on Activity card
        cardRooms.style.transform = 'rotateX(10deg) rotateY(-10deg) scale(0.8) translate3d(20px, 0, 0)';
        cardRooms.style.opacity = '0.2';
        cardRooms.style.filter = 'blur(3px)';
        cardRooms.style.zIndex = '5';

        cardEarnings.style.transform = 'scale(0.85) translate3d(10px, 0, 0)';
        cardEarnings.style.opacity = '0.25';
        cardEarnings.style.filter = 'blur(2px)';
        cardEarnings.style.zIndex = '10';

        cardActivity.style.transform = 'rotateX(0deg) rotateY(0deg) scale(1.1) translate3d(-20px, 0, 0)';
        cardActivity.style.opacity = '1';
        cardActivity.style.filter = 'none';
        cardActivity.style.zIndex = '30';
      }
    }
  } else {
    // Step 5: Transition to Simulator Panel
    if (visualIsometricGroup) {
      visualIsometricGroup.style.opacity = '0';
      visualIsometricGroup.style.pointerEvents = 'none';
      visualIsometricGroup.style.transform = 'scale(0.9)';
    }
    if (visualSimulator) {
      visualSimulator.style.opacity = '1';
      visualSimulator.style.pointerEvents = 'auto';
      visualSimulator.style.transform = 'scale(1)';
    }
  }
}

// Apple-style Parallax Scrolling & Lerp Effect
const parallaxWrappers = document.querySelectorAll('.parallax-wrapper');
const heroBg = document.getElementById('hero-parallax-bg');

// Lerp state
let targetScrollY = 0;
let currentScrollY = 0;
const lerpStrength = 0.08; // Buttery smooth momentum coefficient
let isRequestingFrame = false;

function updateParallax() {
  if (isMobile) {
    // Instant updates on mobile to prevent standard lag/inertia scroll delay feel
    currentScrollY = targetScrollY;
    handleAppleTypographyScroll();
    handleShowcaseScrollytelling();
    isRequestingFrame = false;
    return;
  }

  // Lerp logic for buttery smooth inertial scroll on desktop
  currentScrollY += (targetScrollY - currentScrollY) * lerpStrength;

  // Update our apple typography animation smoothly with the lerped scroll position
  handleAppleTypographyScroll();
  handleShowcaseScrollytelling();

  if (heroBg) {
    // Shift hero background circle gradient
    heroBg.style.transform = `translateY(${currentScrollY * 0.3}px)`;
  }

  parallaxWrappers.forEach(el => {
    const speed = parseFloat(el.getAttribute('data-speed')) || 0;
    // Translate elements based on speed and current lerped scroll
    el.style.transform = `translateY(${currentScrollY * speed}px)`;
  });

  // Continue the frame loop if the difference is noticeable
  if (Math.abs(targetScrollY - currentScrollY) > 0.1) {
    requestAnimationFrame(updateParallax);
  } else {
    currentScrollY = targetScrollY;
    isRequestingFrame = false;
  }
}

window.addEventListener('scroll', () => {
  targetScrollY = window.scrollY;
  if (isMobile) {
    // Run instantly for instantaneous finger matching on mobile
    currentScrollY = targetScrollY;
    handleAppleTypographyScroll();
    handleShowcaseScrollytelling();
  } else if (!isRequestingFrame) {
    isRequestingFrame = true;
    requestAnimationFrame(updateParallax);
  }
}, { passive: true });

// Initial trigger to show elements already in viewport (supporting immediate execution if DOMContentLoaded already fired)
function initializeScripts() {
  targetScrollY = window.scrollY;
  currentScrollY = window.scrollY;
  initScrollReveal();
  handleAppleTypographyScroll();
  handleShowcaseScrollytelling();
  updateParallax();
  initRelatedCarousel();
}

if (document.readyState === 'complete' || document.readyState === 'interactive') {
  initializeScripts();
} else {
  document.addEventListener('DOMContentLoaded', initializeScripts);
}

// Interactive swipable/draggable and navigable related posts carousel
function initRelatedCarousel() {
  const container = document.getElementById('related-carousel-container');
  const prevBtn = document.getElementById('carousel-prev-btn');
  const nextBtn = document.getElementById('carousel-next-btn');

  if (!container) return; // Only run if we are on a post page

  let isDown = false;
  let startX;
  let scrollLeftVal;
  let isInteracting = false;
  let autoScrollTimer = null;
  let resumeTimer = null;

  // Auto-scroll loop
  function stepAutoScroll() {
    if (!isInteracting) {
      container.scrollLeft += 0.8;
      // Loop infinite feel: if reached 50% width of actual elements, reset to 0
      const halfWidth = (container.scrollWidth - container.clientWidth) / 2;
      if (container.scrollLeft >= halfWidth && halfWidth > 0) {
        container.scrollLeft = 0;
      }
    }
    autoScrollTimer = requestAnimationFrame(stepAutoScroll);
  }

  // Start auto scroll
  autoScrollTimer = requestAnimationFrame(stepAutoScroll);

  // Mouse drag handlers
  container.addEventListener('mousedown', (e) => {
    isDown = true;
    isInteracting = true;
    container.style.scrollBehavior = 'auto'; // Disable smooth scroll for active drag
    startX = e.pageX - container.offsetLeft;
    scrollLeftVal = container.scrollLeft;

    if (resumeTimer) clearTimeout(resumeTimer);
  });

  container.addEventListener('mouseleave', () => {
    if (isDown) {
      isDown = false;
      container.style.scrollBehavior = 'smooth';
      resumeAutoScrollDelay();
    }
  });

  container.addEventListener('mouseup', () => {
    if (isDown) {
      isDown = false;
      container.style.scrollBehavior = 'smooth';
      resumeAutoScrollDelay();
    }
  });

  container.addEventListener('mousemove', (e) => {
    if (!isDown) return;
    e.preventDefault();
    const x = e.pageX - container.offsetLeft;
    const walk = (x - startX) * 1.5; // multiplier for satisfying scroll drag
    container.scrollLeft = scrollLeftVal - walk;
  });

  // Touch swipe handlers (for mobile)
  container.addEventListener('touchstart', () => {
    isInteracting = true;
    container.style.scrollBehavior = 'smooth';
    if (resumeTimer) clearTimeout(resumeTimer);
  }, { passive: true });

  container.addEventListener('touchend', () => {
    resumeAutoScrollDelay();
  });

  // Hover pause handlers
  container.addEventListener('mouseenter', () => {
    isInteracting = true;
  });
  container.addEventListener('mouseleave', () => {
    if (!isDown) {
      resumeAutoScrollDelay();
    }
  });

  function resumeAutoScrollDelay() {
    if (resumeTimer) clearTimeout(resumeTimer);
    resumeTimer = setTimeout(() => {
      isInteracting = false;
    }, 3000); // Resume auto scroll 3 seconds after interaction stops
  }

  // Button navigation slide calculations
  const cardWidth = 320 + 24; // Card width (320px) + Gap (24px)

  if (prevBtn) {
    prevBtn.addEventListener('click', () => {
      isInteracting = true;
      container.style.scrollBehavior = 'smooth';
      container.scrollLeft -= cardWidth;
      resumeAutoScrollDelay();
    });
  }

  if (nextBtn) {
    nextBtn.addEventListener('click', () => {
      isInteracting = true;
      container.style.scrollBehavior = 'smooth';
      container.scrollLeft += cardWidth;
      resumeAutoScrollDelay();
    });
  }
}

// Live mockup list animator (Component Loop Animation - Clean, Big Typography!)
const mockupSessions = [
  { initials: 'MY', name: 'Melis Hanım', details: 'Yüz Yüze • Oda 3', fee: 1800, status: 'Ödendi', statusClass: 'text-emerald-800 bg-emerald-100', color: 'bg-[#6b705c]/15 text-[#6b705c]' },
  { initials: 'OD', name: 'Ömer Bey', details: 'İnternet Üzerinden Seans', fee: 1500, status: 'Bekliyor', statusClass: 'text-amber-800 bg-amber-100', color: 'bg-[#cb997e]/15 text-[#cb997e]' },
  { initials: 'CK', name: 'Canan Hanım', details: 'Çocuk Seansı • Oda 1', fee: 2000, status: 'Ödendi', statusClass: 'text-emerald-800 bg-emerald-100', color: 'bg-slate-900/15 text-slate-900' },
  { initials: 'BC', name: 'Berk Bey', details: 'Çift Seansı • Oda 4', fee: 2500, status: 'Ödendi', statusClass: 'text-emerald-800 bg-emerald-100', color: 'bg-[#6b705c]/15 text-[#6b705c]' },
  { initials: 'SB', name: 'Selin Hanım', details: 'Online Görüşme', fee: 1900, status: 'Bekliyor', statusClass: 'text-amber-800 bg-amber-100', color: 'bg-[#cb997e]/15 text-[#cb997e]' }
];

let currentSessionIndex = 2; // start by replacing/adding
const mockupListContainer = document.querySelector('#hero-mockup-wrapper .space-y-4');

// Stats variables in mockup (referenced directly by clear IDs!)
const mockStatGross = document.getElementById('mock-stat-gross-val');
const mockStatRent = document.getElementById('mock-stat-rent-val');
const mockStatNet = document.getElementById('mock-stat-net-val');

let activeGrossVal = 32400;
let activeRentVal = 5400;
let activeNetVal = 27000;

function animateMockupComponent() {
  if (!mockupListContainer) return;

  const itemToInsert = mockupSessions[currentSessionIndex];

  // Create new element with fade class
  const newCard = document.createElement('div');
  newCard.className = 'flex items-center justify-between p-4 bg-white border border-slate-200 rounded-2xl hover:border-slate-400 transition-all opacity-0 -translate-y-4 duration-500 shadow-2xs';
  newCard.innerHTML = `
    <div class='flex items-center gap-4.5'>
      <div class='w-12 h-12 rounded-full ${itemToInsert.color} flex items-center justify-center text-sm font-black'>${itemToInsert.initials}</div>
      <div>
        <span class='text-sm sm:text-base font-black text-slate-900 block'>${itemToInsert.name}</span>
        <span class='text-xs text-slate-500 font-bold'>${itemToInsert.details}</span>
      </div>
    </div>
    <div class='text-right'>
      <span class='text-base font-black text-slate-900 block'>₺${itemToInsert.fee.toLocaleString('tr-TR')}</span>
      <span class='text-xs font-bold ${itemToInsert.statusClass} px-3 py-1 rounded-full border border-emerald-200/30'>${itemToInsert.status}</span>
    </div>
  `;

  // Remove the last child of list container and insert the new one at the top
  if (mockupListContainer.children.length >= 2) {
    const lastChild = mockupListContainer.lastElementChild;
    if (lastChild) {
      lastChild.classList.add('opacity-0', 'translate-y-4');
      setTimeout(() => {
        if (lastChild.parentNode === mockupListContainer) {
          mockupListContainer.removeChild(lastChild);
        }
        mockupListContainer.insertBefore(newCard, mockupListContainer.firstChild);
        // Trigger transition
        setTimeout(() => {
          newCard.classList.remove('opacity-0', '-translate-y-4');
        }, 50);
      }, 300);
    }
  } else {
    mockupListContainer.insertBefore(newCard, mockupListContainer.firstChild);
    setTimeout(() => {
      newCard.classList.remove('opacity-0', '-translate-y-4');
    }, 50);
  }

  // Update the mock stats nicely
  activeGrossVal += itemToInsert.fee;
  const rentFeeForSession = itemToInsert.details.includes('Online') || itemToInsert.details.includes('İnternet') ? 0 : 350;
  activeRentVal += rentFeeForSession;
  activeNetVal = activeGrossVal - activeRentVal;

  // Smooth value transitions in UI
  if (mockStatGross) mockStatGross.textContent = "₺" + activeGrossVal.toLocaleString('tr-TR');
  if (mockStatRent) mockStatRent.textContent = "₺" + activeRentVal.toLocaleString('tr-TR');
  if (mockStatNet) mockStatNet.textContent = "₺" + activeNetVal.toLocaleString('tr-TR');

  // Loop to next item
  currentSessionIndex = (currentSessionIndex + 1) % mockupSessions.length;
}

// Run component loop every 4 seconds
setInterval(animateMockupComponent, 4000);

