// ==========================================
// Interactive Room Permission & Booking Simulator (Desktop + Mobile Sync)
// ==========================================
const permissions = {
  melis: { std: true, play: true },
  ozgur: { std: true, play: false }
};

let bookingTimeout = null;

window.togglePermission = function(therapist, type) {
  const active = !permissions[therapist][type];
  permissions[therapist][type] = active;

  // Update both desktop and mobile buttons if they exist
  const btnIdDesk = `btn-perm-${therapist}-${type}`;
  const btnIdMob = `btn-perm-${therapist}-${type}-mob`;

  [btnIdDesk, btnIdMob].forEach(btnId => {
    const btn = document.getElementById(btnId);
    if (btn) {
      if (active) {
        btn.className = 'px-2 py-1 text-[10px] font-black rounded-lg border transition-all bg-emerald-50 text-emerald-800 border-emerald-200 flex items-center gap-1 cursor-pointer shadow-2xs';
        btn.innerHTML = `<span>✓ ${type === 'std' ? 'Standart' : 'Oyun Ter.'}</span>`;
      } else {
        btn.className = 'px-2 py-1 text-[10px] font-black rounded-lg border transition-all bg-red-50 text-red-800 border-red-200 flex items-center gap-1 cursor-pointer shadow-2xs';
        btn.innerHTML = `<span>✗ ${type === 'std' ? 'Standart' : 'Oyun Ter.'}</span>`;
      }
    }
  });

  const therapistName = therapist === 'melis' ? 'Melis Hanım' : 'Özgür Bey';
  const typeName = type === 'std' ? 'Standart Oda' : 'Oyun Odası';
  updateSimConsole(`GÜNCELLEME: ${therapistName} için ${typeName} kapısı ${active ? 'AÇILDI! 🎉' : 'KİLİTLENDİ! 🔒'}`, 'text-[#cb997e]');
}

window.simulateBooking = function(therapist, type) {
  if (bookingTimeout) clearTimeout(bookingTimeout);
  resetSimRooms();

  const therapistName = therapist === 'melis' ? 'Melis Hanım' : 'Özgür Bey';
  const roomNum = type === 'std' ? 1 : 2;

  // Select elements for both targets
  const roomElDesk = document.getElementById(`sim-room-${roomNum}`);
  const badgeElDesk = document.getElementById(`sim-room-${roomNum}-badge`);
  const descElDesk = document.getElementById(`sim-room-${roomNum}-desc`);

  const roomElMob = document.getElementById(`sim-room-${roomNum}-mob`);
  const badgeElMob = document.getElementById(`sim-room-${roomNum}-badge-mob`);
  const descElMob = document.getElementById(`sim-room-${roomNum}-desc-mob`);

  updateSimConsole(`iCal BAĞLANTISI: ${therapistName} takviminden seans rezervasyonu algılandı... (#Oda${roomNum})`, 'text-slate-200');

  const isAuthorized = permissions[therapist][type];

  setTimeout(() => {
    if (isAuthorized) {
      updateSimConsole(`HARİKA! ${therapistName} için odaya giriş izni onaylandı. Seans başarıyla işlendi. ✅`, 'text-emerald-400');

      if (roomElDesk && badgeElDesk && descElDesk) {
        roomElDesk.className = 'p-3 bg-emerald-50/20 border border-emerald-200 rounded-xl flex flex-col justify-between h-[85px] transition-all scale-102';
        badgeElDesk.className = 'text-[10px] px-2 py-0.5 bg-emerald-500 text-white font-bold rounded-md';
        badgeElDesk.textContent = 'DOLU 🟢';
        descElDesk.className = 'text-[10px] text-emerald-800 font-bold';
        descElDesk.textContent = `${therapistName} İçeride`;
      }

      if (roomElMob && badgeElMob && descElMob) {
        roomElMob.className = 'p-2.5 bg-emerald-50/20 border border-emerald-200 rounded-xl flex flex-col justify-between h-[80px] transition-all scale-102';
        badgeElMob.className = 'text-[8px] px-1.5 py-0.5 bg-emerald-500 text-white font-bold rounded-md';
        badgeElMob.textContent = 'DOLU 🟢';
        descElMob.className = 'text-[8px] text-emerald-800 font-bold';
        descElMob.textContent = `${therapistName} İçeride`;
      }

      bookingTimeout = setTimeout(() => {
        resetSimRooms();
      }, 4500);

    } else {
      updateSimConsole(`ENGEL: ${therapistName} bu oda tipi için yetkili değil! Giriş talebi durduruldu. ❌`, 'text-red-400');

      if (roomElDesk && badgeElDesk && descElDesk) {
        roomElDesk.className = 'p-3 bg-red-50/20 border border-red-200 rounded-xl flex flex-col justify-between h-[85px] transition-all shake-element';
        badgeElDesk.className = 'text-[10px] px-2 py-0.5 bg-red-500 text-white font-bold rounded-md';
        badgeElDesk.textContent = 'KİLİTLİ 🔒';
        descElDesk.className = 'text-[10px] text-red-800 font-bold';
        descElDesk.textContent = 'Giriş İzni Yok!';
      }

      if (roomElMob && badgeElMob && descElMob) {
        roomElMob.className = 'p-2.5 bg-red-50/20 border border-red-200 rounded-xl flex flex-col justify-between h-[80px] transition-all shake-element';
        badgeElMob.className = 'text-[8px] px-1.5 py-0.5 bg-red-500 text-white font-bold rounded-md';
        badgeElMob.textContent = 'KİLİTLİ 🔒';
        descElMob.className = 'text-[8px] text-red-800 font-bold';
        descElMob.textContent = 'Giriş İzni Yok!';
      }

      bookingTimeout = setTimeout(() => {
        resetSimRooms();
      }, 4500);
    }
  }, 800);
}

