    r2bMob.className = 'text-[8px] px-1.5 py-0.5 bg-emerald-100 text-emerald-800 font-bold rounded-md';
    r2bMob.textContent = 'BOŞ';
    r2dMob.className = 'text-[8px] text-slate-500 font-bold';
