function updateSimConsole(message, colorClass) {
  const consoleElDesk = document.getElementById('sim-console');
  const consoleElMob = document.getElementById('sim-console-mob');

  [consoleElDesk, consoleElMob].forEach(consoleEl => {
    if (consoleEl) {
      consoleEl.innerHTML = `
        <span class='${colorClass} font-bold mb-0.5'>&gt; ${message}</span>
        <span class='text-slate-400 font-medium'>Yetkileri değiştirip seans gönderin.</span>
      `;
    }
  });
}
